class Solution:
    def lexSmallestNegatedPerm(self, n, target):
        S = n * (n + 1) // 2
        if (S - target) % 2 != 0:
            return []
        t = (S - target) // 2
        if t < 0 or t > S:
            return []
        negated = [False] * (n + 1)
        R = t
        for v in range(n, 0, -1):
            rem_sum = (v - 1) * v // 2
            if 0 <= R - v <= rem_sum:
                negated[v] = True
                R -= v
        neg_vals = sorted((v for v in range(1, n + 1) if negated[v]), reverse=True)
        pos_vals = sorted(v for v in range(1, n + 1) if not negated[v])
        return [-v for v in neg_vals] + pos_vals

