var lexSmallestNegatedPerm = function(n, target) {
    const S = n * (n + 1) / 2;
    if ((S - target) % 2 !== 0) return [];
    const t = (S - target) / 2;
    if (t < 0 || t > S) return [];
    const negated = new Array(n + 1).fill(false);
    let R = t;
    for (let v = n; v >= 1; v--) {
        const remSum = (v - 1) * v / 2;
        if (R - v >= 0 && R - v <= remSum) {
            negated[v] = true;
            R -= v;
        }
    }
    const negVals = [];
    const posVals = [];
    for (let v = 1; v <= n; v++) {
        if (negated[v]) negVals.push(v);
        else posVals.push(v);
    }
    negVals.sort((a, b) => b - a);
    posVals.sort((a, b) => a - b);
    return negVals.map(v => -v).concat(posVals);
};
